document.querySelectorAll('.faq-trigger').forEach((trigger) => {
  trigger.addEventListener('click', () => {
    const panel = document.getElementById(trigger.getAttribute('aria-controls'));
    const isOpen = trigger.getAttribute('aria-expanded') === 'true';

    trigger.setAttribute('aria-expanded', String(!isOpen));
    panel.hidden = isOpen;
    panel.classList.toggle('is-open', !isOpen);
  });
});

:root {
  --hero-space-y: clamp(3rem, 8vw, 6rem);
  --hero-space-x: clamp(1rem, 4vw, 3rem);
  --hero-title-size: clamp(2.5rem, 6vw, 5rem);
  --hero-copy-size: clamp(1rem, 2vw, 1.25rem);
}

.hero {
  padding: var(--hero-space-y) var(--hero-space-x);
  display: grid;
  gap: 1.5rem;
  align-content: center;
}

.hero-title {
  font-size: var(--hero-title-size);
  line-height: 0.95;
}

.hero-copy {
  max-width: 60ch;
  font-size: var(--hero-copy-size);
}
